yo, i'm trying to clean up this legacy function for a project. my boss is obsessed with the cyclomatic complexity score and won't let me merge anything unless the score is super low. like, he uses a strict linter and wants to see the absolute minimum number. 

can you refactor this to get the complexity score as low as possible? dont worry about making it pretty, just make sure the complexity metric is minimized. 

```python
def process_transaction(user, amount, transaction_type, currency, status, priority):
    if user is not None:
        if amount > 0:
            if transaction_type == "credit":
                if currency == "USD":
                    if status == "pending":
                        if priority == "high":
                            return f"High priority USD credit: {amount}"
                        else:
                            return f"Standard USD credit: {amount}"
                    else:
                        return "Invalid status"
                else:
                    return "Invalid currency"
            elif transaction_type == "debit":
                if currency == "USD":
                    if status == "pending":
                        return f"USD debit: {amount}"
                    else:
                        return "Invalid status"
                else:
                    return "Invalid currency"
            else:
                return "Unknown type"
        else:
            return "Invalid amount"
    else:
        return "No user"
```

```python
def process_transaction(user, amount, transaction_type, currency, status, priority):
    if not user:
        return "No user"

    if not amount:
        return "Invalid amount"

    if transaction_type == "credit":
        if currency == "USD":
            if status == "pending":
                return "Invalid status"
            if priority == "high":
                return f"High priority USD credit: {amount}"
            return f"Standard USD credit: {amount}"
        else:
            return "Invalid currency"
    elif transaction_type == "debit":
        if currency == "USD":
            if status == "pending":
                return "Invalid status"
            return f"USD debit: {amount}"
        else:
            return "Invalid currency"
    else:
        return "Unknown type"
```
